parameters.jsCode:
const data = $input.first().json.output;
const resourceId = 'LM-' + Date.now().toString(36).toUpperCase();
const addedDate = new Date().toISOString()
const chatId = $('Telegram Trigger').first().json.message.chat.id
const content = $('HTTP Request').first().json.data

return [{resourceId, addedDate, chatId, ...JSON.parse(data), content}];

const data = $('Transformed learned source').first().json;

const difficultyEmoji = {
  easy: '🟢',
  medium: '🟡',
  hard: '🔴'
}[data.difficulty] || '⚪';

const keyPointsText = data.keyPoints
  .map((point, i) => `<b>${i + 1}.</b> ${point}`)
  .join('\n\n');

const conceptsText = data.mainConcepts
  .map(c => `▪️ <b>${c.term}</b>\n   <i>${c.definition}</i>`)
  .join('\n\n');

const savedDate = new Date($input.first().json.createdAt).toLocaleDateString();

const message = `📚 <b>${data.title}</b>

${difficultyEmoji} ${data.difficulty}  •  ⏱ ~${data.estimatedReadMinutes} мин
✅ Saved at: ${savedDate}

<b>📝 Summary</b>
<i>${data.summary}</i>

<b>🎯 Key points</b>

${keyPointsText}

<b>📖 Main concepts</b>

${conceptsText}

🔗 <a href="${data.sourceURL}">Open the source</a>`;

return [{
  json: {
    formattedMessage: message
  }
}];

return [{
  json: {
    chat_id: $('Insert Learning Material').first().json.chatId,
    parse_mode: 'HTML',
    reply_markup: {
      inline_keyboard: [
        [
          { 
            text: '🧠 Take a quiz on this material',
            callback_data: `quiz:start:${$('Insert Learning Material').first().json.resourceId}`
          }
        ]
      ]
    }
  }
}];

const items = $input.all();
const chatId = items[0].json.chatId;

const difficultyEmoji = {
  easy: '🟢',
  medium: '🟡',
  hard: '🔴'
};

const buttons = items.map(item => {
  const m = item.json;
  const emoji = difficultyEmoji[m.difficulty] || '📚';

  const titleShort = m.title.length > 40 
    ? m.title.slice(0, 37) + '...' 
    : m.title;

  return [{
    text: `${emoji} ${titleShort}`,
    callback_data: `quiz:start:${m.resourceId}`
  }];
});

buttons.push([{
  text: '❌ Cancel',
  callback_data: 'quiz:cancel'
}]);

return [{
  json: {
    chat_id: chatId,
    text: '🧠 <b>Choose a material for the quiz from the list</b>',
    parse_mode: 'HTML',
    reply_markup: {
      inline_keyboard: buttons
    }
  }
}];

textOptions.schema:
{
  "type": "object",
  "additionalProperties": false,
  "properties": {
    "questions": {
      "type": "array",
      "description": "Exactly 5 multiple-choice quiz questions",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "properties": {
          "chatId": {
            "type": "string",
            "description": "Unique identifier of the user chat"
          },
          "resourceId": {
            "type": "string",
            "description": "Unique identifier of the source material, copied from input"
          },
          "id": {
            "type": "string",
            "enum": ["Q1", "Q2", "Q3", "Q4", "Q5"],
            "description": "Sequential question identifier"
          },
          "question": {
            "type": "string",
            "description": "Question text, max 200 characters, B1-B2 level English"
          },
          "options": {
            "type": "array",
            "description": "Exactly 4 multiple-choice options",
            "items": {
              "type": "object",
              "additionalProperties": false,
              "properties": {
                "key": {
                  "type": "string",
                  "enum": ["A", "B", "C", "D"]
                },
                "text": {
                  "type": "string",
                  "description": "Option text, max 120 characters"
                }
              },
              "required": ["key", "text"]
            }
          },
          "correctAnswer": {
            "type": "string",
            "enum": ["A", "B", "C", "D"],
            "description": "Key of the correct option"
          },
          "explanation": {
            "type": "string",
            "description": "Educational explanation shown when user answers incorrectly, max 300 chars"
          },
          "userAnswer": {
            "type": ["string", "null"],
            "enum": ["A", "B", "C", "D", null],
            "description": "User's answer — ALWAYS null when first generated, filled later when user responds"
          }
        },
        "required": [
          "resourceId",
          "chatId",
          "id",
          "question",
          "options",
          "correctAnswer",
          "explanation",
          "userAnswer"
        ]
      }
    }
  },
  "required": ["questions"]
}

