const content = $input.first().json.data;

const cleaned = content
  // Markdown изображения
  .replace(/!\[.*?\]\(.*?\)/g, '')
  .replace(/!\[.*?\]\[.*?\]/g, '')

  // HTML img/picture/figure/svg
  .replace(/<img\b[^>]*\/?>/gi, '')
  .replace(/<picture\b[^>]*>[\s\S]*?<\/picture>/gi, '')
  .replace(/<figure\b[^>]*>[\s\S]*?<\/figure>/gi, '')
  .replace(/<svg\b[^>]*>[\s\S]*?<\/svg>/gi, '')

  // Ссылки на изображения (jpg, png, gif, webp, svg, ico, bmp)
  .replace(/https?:\/\/\S+\.(jpg|jpeg|png|gif|webp|svg|ico|bmp|avif)(\?\S*)?/gi, '')

  // base64-картинки
  .replace(/data:image\/[^;]+;base64,[A-Za-z0-9+/=]+/g, '')

  // Чистка лишних пробелов и пустых строк
  .replace(/\n{3,}/g, '\n\n')
  .replace(/[ \t]+/g, ' ')
  .trim();

return [{ json: { ...$input.first().json, content: cleaned } }];

const data = JSON.parse($input.first().json.output) || {};

const questions = data.questions || [];

return questions.map(q => ({
  json: {
    id: `${q.resourceId}-${q.id}`,
    quizId: q.id,
    chatId: $('Telegram Trigger').first().json.callback_query.message.chat.id,
    resourceId: q.resourceId, 
    correctAnswer: q.correctAnswer,
    explanation: q.explanation,
    question: q.question,
    options: JSON.stringify(q.options),  
    userAnswer: null
  }
}));

const questions = $input.all();

const firstQ = questions.find(q => q.json.quizId === "Q1");

return [
  {
    json: {
      quizId: firstQ?.json?.quizId,
      resourceId: firstQ?.json?.resourceId,
      question: firstQ?.json?.question,
      options: JSON.parse(firstQ?.json?.options || '')
    }
  }
];

const item = $('Update question by user answer').first().json;

const isUserAnswerCorrect = item.correctAnswer === item.userAnswer;
let resultMessage;

if (isUserAnswerCorrect) {
  resultMessage = "🎉 All good! Your answer is correct.";
} else {
  resultMessage =
    `❌ ${item.userAnswer} is incorrect.\n\n` +
    `✔️ Correct answer: <b>${item.correctAnswer}</b>\n` +
    `💡 Explanation: <i>${item.explanation || 'No explanation provided.'}</i>`;
}

const allQuestions = $input.all().map(i => i.json);
let correctAnswers = 0;
let allAnswered = 0;

for (const q of allQuestions) {
  const isCorrect = q.userAnswer === q.correctAnswer;

  if(q.userAnswer) {
    allAnswered++
  }

  if (isCorrect) {
    correctAnswers++;
  }
}

const scorePercent = Math.round(
  (correctAnswers / allQuestions.length) * 100
);

const scoreMessage =
  `\n📊 <b>Quiz Result</b>\n` +
  `Answered: <b>${allAnswered}/${allQuestions.length}</b>\n` +
  `✔️ Correct answers: <b>${correctAnswers}/${allQuestions.length}</b>\n` +
  `📈 Score: <b>${scorePercent}%</b>`;


return [
  {
    json: {
      resultMessage,
      scoreMessage
    }
  }
];

const allQuestions = $('Get all questions for quiz').all();

const nextQuestion = allQuestions.sort((a, b) => {
  const aNum = Number(a.json.quizId.replace('Q', ''));
  const bNum = Number(b.json.quizId.replace('Q', ''));
  return aNum - bNum;
}).find(
  q => q.json.userAnswer === null || q.json.userAnswer === undefined

);

return [
  {
    json: {
      isAllCompleted: !nextQuestion,
      nextQuestion: {
      quizId: nextQuestion?.json?.quizId,
      resourceId: nextQuestion?.json?.resourceId,
      question: nextQuestion?.json?.question,
      options: nextQuestion ? JSON.parse(nextQuestion?.json?.options || '') : ''
      } 
    }
  }
];

